def add_fields(self, *fields: Any) -> None:
        to_add: deque[Any] = deque(fields)

        while to_add:
            rec = to_add.popleft()

            if isinstance(rec, io.IOBase):
                k = guess_filename(rec, "unknown")
                self.add_field(k, rec)  # type: ignore[arg-type]

            elif isinstance(rec, (MultiDictProxy, MultiDict)):
                to_add.extend(rec.items())

            elif isinstance(rec, (list, tuple)) and len(rec) == 2:
                k, fp = rec
                self.add_field(k, fp)

            else:
                raise TypeError(
                    "Only io.IOBase, multidict and (name, file) "
                    "pairs allowed, use .add_field() for passing "
                    f"more complex parameters, got {rec!r}"
                )

def parse(self):
        rargs = [arg for arg in self.args if arg]
        pos = 0
        while pos < len(rargs):
            arg = rargs[pos]
            if arg == '--':
                self.passthrough = ' '.join(rargs[pos:])
                break
            elif arg[0] == '-':
                if arg[1] == '-':
                    self.process_long_opt(arg[2:])
                else:
                    value = None
                    if len(rargs) > pos + 1 and rargs[pos + 1][0] != '-':
                        value = rargs[pos + 1]
                        pos += 1
                    self.process_short_opt(arg[1:], value)
            else:
                self.values.append(arg)
            pos += 1

def _bootstrap_inner(self):
        try:
            self._set_ident()
            if _HAVE_THREAD_NATIVE_ID:
                self._set_native_id()
            self._set_os_name()
            self._started.set()
            with _active_limbo_lock:
                _active[self._ident] = self
                del _limbo[self]

            if _trace_hook:
                _sys.settrace(_trace_hook)
            if _profile_hook:
                _sys.setprofile(_profile_hook)

            try:
                self._context.run(self.run)
            except:
                self._invoke_excepthook(self)
        finally:
            self._delete()

def read_json_value(data: ReadBuffer) -> JsonValue:
    tag = read_tag(data)
    if tag == LITERAL_NONE:
        return None
    if tag == LITERAL_FALSE:
        return False
    if tag == LITERAL_TRUE:
        return True
    if tag == LITERAL_INT:
        return read_int_bare(data)
    if tag == LITERAL_STR:
        return read_str_bare(data)
    if tag == LIST_GEN:
        size = read_int_bare(data)
        return [read_json_value(data) for _ in range(size)]
    if tag == TUPLE_GEN:
        size = read_int_bare(data)
        return tuple(read_json_value(data) for _ in range(size))
    if tag == DICT_STR_GEN:
        size = read_int_bare(data)
        return {read_str_bare(data): read_json_value(data) for _ in range(size)}
    assert False, f"Invalid JSON tag: {tag}"

def _writelines(
        self,
        chunks: Iterable[
            Union[bytes, bytearray, "memoryview[int]", "memoryview[bytes]"]
        ],
    ) -> None:
        size = 0
        for chunk in chunks:
            size += len(chunk)
        self.buffer_size += size
        self.output_size += size
        transport = self._protocol.transport
        if transport is None or transport.is_closing():
            raise ClientConnectionResetError("Cannot write to closing transport")
        if SKIP_WRITELINES or size < MIN_PAYLOAD_FOR_WRITELINES:
            transport.write(b"".join(chunks))
        else:
            transport.writelines(chunks)

async def write(self, chunk: bytes) -> None:
        if self._compress is not None:
            if chunk:
                chunk = await self._compress.compress(chunk)
                if not chunk:
                    return

        if self._encoding == "base64":
            buf = self._encoding_buffer
            assert buf is not None
            buf.extend(chunk)

            if buf:
                div, mod = divmod(len(buf), 3)
                enc_chunk, self._encoding_buffer = (buf[: div * 3], buf[div * 3 :])
                if enc_chunk:
                    b64chunk = base64.b64encode(enc_chunk)
                    await self._writer.write(b64chunk)
        elif self._encoding == "quoted-printable":
            await self._writer.write(binascii.b2a_qp(chunk))
        else:
            await self._writer.write(chunk)

def log(self, request: BaseRequest, response: StreamResponse, time: float) -> None:
        try:
            fmt_info = self._format_line(request, response, time)

            values = list()
            extra: dict[str, str | dict[str, str]] = dict()
            for key, value in fmt_info:
                values.append(value)

                if isinstance(key, str):
                    extra[key] = value
                else:
                    k1, k2 = key
                    dct: dict[str, str] = extra.get(k1, {})  # type: ignore[assignment]
                    dct[k2] = value
                    extra[k1] = dct

            self.logger.info(self._log_format % tuple(values), extra=extra)
        except Exception:
            self.logger.exception("Error in logging")

async def _start(self, request: "BaseRequest") -> AbstractStreamWriter:
        if hdrs.CONTENT_LENGTH in self._headers:
            if should_remove_content_length(request.method, self.status):
                del self._headers[hdrs.CONTENT_LENGTH]
        elif not self._chunked:
            if isinstance(self._body, Payload):
                if (size := self._body.size) is not None:
                    self._headers[hdrs.CONTENT_LENGTH] = str(size)
            else:
                body_len = len(self._body) if self._body else "0"
                # https://www.rfc-editor.org/rfc/rfc9110.html#section-8.6-7
                if body_len != "0" or (
                    self.status != 304 and request.method not in hdrs.METH_HEAD_ALL
                ):
                    self._headers[hdrs.CONTENT_LENGTH] = str(body_len)

        return await super()._start(request)

def human_write_stats(self):
        if self.write_stats is None:
            return 'N/A'
        vals = list(self.write_stats.values())
        total = sum(vals)

        def per(v, total):
            return f'{(float(v) / total) if v else 0:.2f}'

        return {
            'total': total,
            'avg': per(total / len(self.write_stats) if total else 0, total),
            'all': ', '.join(per(v, total) for v in vals),
            'raw': ', '.join(map(str, vals)),
            'strategy': SCHED_STRATEGY_TO_NAME.get(
                self.sched_strategy, self.sched_strategy,
            ),
            'inqueues': {
                'total': len(self._all_inqueues),
                'active': len(self._active_writes),
            }
        }

def __eq__(self, other: object) -> bool:
        return (
            isinstance(other, GraphQLError)
            and self.__class__ == other.__class__
            and all(
                getattr(self, slot) == getattr(other, slot)
                for slot in self.__slots__
                if slot != "original_error"
            )
        ) or (
            isinstance(other, dict)
            and "message" in other
            and all(
                slot in self.__slots__ and getattr(self, slot) == other.get(slot)
                for slot in other
                if slot != "original_error"
            )
        )

def leave_operation_definition(node: PrintedNode, *_args: Any) -> str:
        var_defs = (
            wrap("(\n", join(node.variable_definitions, "\n"), "\n)")
            if has_multiline_items(node.variable_definitions)
            else wrap("(", join(node.variable_definitions, ", "), ")")
        )
        prefix = wrap("", node.description, "\n") + join(
            (
                node.operation.value,
                join((node.name, var_defs)),
                join(node.directives, " "),
            ),
            " ",
        )
        # Anonymous queries with no directives or variable definitions can use the
        # query short form.
        return ("" if prefix == "query" else prefix + " ") + node.selection_set

def find_union_type_changes(
    old_type: GraphQLUnionType, new_type: GraphQLUnionType
) -> list[SchemaChange]:
    schema_changes: list[SchemaChange] = []
    possible_types_diff = list_diff(old_type.types, new_type.types)

    schema_changes.extend(
        DangerousChange(
            DangerousChangeType.TYPE_ADDED_TO_UNION,
            f"{possible_type} was added to union type {old_type}.",
        )
        for possible_type in possible_types_diff.added
    )

    schema_changes.extend(
        BreakingChange(
            BreakingChangeType.TYPE_REMOVED_FROM_UNION,
            f"{possible_type} was removed from union type {old_type}.",
        )
        for possible_type in possible_types_diff.removed
    )

    return schema_changes

def map_fields(
        field_map: dict[str, GraphQLField], parent_type_name: str
    ) -> dict[str, GraphQLField]:
        new_field_map = {}
        mapper = config_mapper_map.get(SchemaElementKind.FIELD)
        for field_name, field in field_map.items():
            mapped_field = merge_kwargs(
                field.to_kwargs(),
                type_=get_type(cast("GraphQLNamedType", field.type)),
                args=map_args(field.args, parent_type_name, field_name),
            )
            if mapper is not None:
                mapped_field = mapper(mapped_field, parent_type_name)
            new_field_map[field_name] = GraphQLField(**mapped_field)
        return new_field_map

def map_args(
        argument_map: dict[str, GraphQLArgument],
        field_or_directive_name: str,
        parent_type_name: str | None = None,
    ) -> dict[str, GraphQLArgument]:
        new_argument_map = {}
        mapper = config_mapper_map.get(SchemaElementKind.ARGUMENT)
        for arg_name, arg in argument_map.items():
            mapped_arg = merge_kwargs(
                arg.to_kwargs(), type_=get_type(cast("GraphQLNamedType", arg.type))
            )
            if mapper is not None:
                mapped_arg = mapper(
                    mapped_arg, field_or_directive_name, parent_type_name
                )
            new_argument_map[arg_name] = GraphQLArgument(**mapped_arg)
        return new_argument_map

def __init__(
self,
value: TextIO,
*args: Any,
encoding: str | None = None,
content_type: str | None = None,
**kwargs: Any,
) -> None:
if encoding is None:
    if content_type is None:
        encoding = "utf-8"
        content_type = "text/plain; charset=utf-8"
    else:
        mimetype = parse_mimetype(content_type)
        encoding = mimetype.parameters.get("charset", "utf-8")
else:
    if content_type is None:
        content_type = "text/plain; charset=%s" % encoding

super().__init__(
    value,
    content_type=content_type,
    encoding=encoding,
    *args,
    **kwargs,
)

def __getitem__(self, key):
        # type: (str) -> Any
        keys = self._to_keys(key)
        getitem = super().__getitem__
        for k in keys + (
                tuple(f(key) for f in self._keys) if self._keys else ()):
            try:
                return getitem(k)
            except KeyError:
                pass
        try:
            # support subclasses implementing __missing__
            return self.__missing__(key)
        except KeyError:
            if len(keys) > 1:
                raise KeyError(
                    'Key not found: {0!r} (with prefix: {0!r})'.format(*keys))
            raise

def _find_vc2015():
    try:
        key = winreg.OpenKeyEx(
            winreg.HKEY_LOCAL_MACHINE,
            r"Software\Microsoft\VisualStudio\SxS\VC7",
            access=winreg.KEY_READ | winreg.KEY_WOW64_32KEY,
        )
    except OSError:
        log.debug("Visual C++ is not registered")
        return None, None

    best_version = 0
    best_dir = None
    with key:
        for i in count():
            try:
                v, vc_dir, vt = winreg.EnumValue(key, i)
            except OSError:
                break
            if v and vt == winreg.REG_SZ and os.path.isdir(vc_dir):
                try:
                    version = int(float(v))
                except (ValueError, TypeError):
                    continue
                if version >= 14 and version > best_version:
                    best_version, best_dir = version, vc_dir
    return best_version, best_dir

def _replace_charref(s):
    s = s.group(1)
    if s[0] == '#':
        # numeric charref
        if s[1] in 'xX':
            num = int(s[2:].rstrip(';'), 16)
        else:
            num = int(s[1:].rstrip(';'))
        if num in _invalid_charrefs:
            return _invalid_charrefs[num]
        if 0xD800 <= num <= 0xDFFF or num > 0x10FFFF:
            return '\uFFFD'
        if num in _invalid_codepoints:
            return ''
        return chr(num)
    else:
        # named charref
        if s in _html5:
            return _html5[s]
        # find the longest matching name (as defined by the standard)
        for x in range(len(s)-1, 1, -1):
            if s[:x] in _html5:
                return _html5[s[:x]] + s[x:]
        else:
            return '&' + s

